mapper.select:
/* com.erns.coching.raw.mapper.RawDAO.getElmList */
SELECT
, ID.REP_NAME AS ELM_NAME , ID.REP_NAME_EN AS ELM_NAME_EN , ID.CAS_NO FROM T_RAW_ELEMENT_INF BB INNER JOIN T_RAW_MST AA ON AA.RAW_SEQ = BB.RAW_SEQ INNER JOIN T_INGD_DIC ID ON BB.RAW_ELM_ID = ID.ID
AND BB.RAW_SEQ = #{rawSeq , jdbcType=INTEGER}

/* com.erns.coching.raw.mapper.RawDAO.getDocList */

SELECT

FROM  T_RAW_DOC DD
INNER JOIN T_RAW_MST AA
ON AA.RAW_SEQ = DD.RAW_SEQ

	AND DD.RAW_SEQ 	= #{rawSeq	, jdbcType=INTEGER}

/* com.erns.coching.raw.mapper.RawDAO.getTypeList */ SELECT
, CT.CODE_NM_KO , CT.CODE_NM_EN FROM T_RAW_TYPE_INF CC INNER JOIN T_RAW_MST AA ON AA.RAW_SEQ = CC.RAW_SEQ INNER JOIN T_CM_RAW_TYPE CT ON CC.GRP_CODE = CT.GRP_CODE AND CC.CODE = CT.CODE
AND CC.RAW_SEQ = #{rawSeq , jdbcType=INTEGER}

/* com.erns.coching.raw.mapper.RawDAO.getManagerList */
SELECT
, MI.MEMB_NAME FROM T_RAW_MANAGER EE INNER JOIN T_RAW_MST AA ON AA.RAW_SEQ = EE.RAW_SEQ INNER JOIN T_MEMB_INF MI ON EE.MEMB_SEQ = MI.MEMB_SEQ
AND EE.RAW_SEQ = #{rawSeq , jdbcType=INTEGER}

/* com.erns.coching.raw.mapper.RawDAO.getManager */

SELECT

FROM  T_RAW_MANAGER EE
INNER JOIN T_RAW_MST AA
ON AA.RAW_SEQ = EE.RAW_SEQ

	AND EE.RAW_SEQ 	= #{rawSeq	, jdbcType=INTEGER}
	AND EE.MEMB_SEQ 	= #{membSeq	, jdbcType=INTEGER}

/* com.erns.coching.raw.mapper.RawDAO.getDetail */ SELECT
FROM T_RAW_DETAIL FF INNER JOIN T_RAW_MANAGER EE ON EE.RAW_SEQ = FF.RAW_SEQ AND EE.MEMB_SEQ = FF.MEMB_SEQ INNER JOIN T_RAW_MST AA ON AA.RAW_SEQ = FF.RAW_SEQ
AND FF.DEL_YN = 'N' AND FF.RAW_DETAIL_SEQ = #{rawDetailSeq , jdbcType=INTEGER}

/* com.erns.coching.raw.mapper.RawDAO.getDetail */ SELECT
FROM T_RAW_DETAIL FF INNER JOIN T_RAW_MANAGER EE ON EE.RAW_SEQ = FF.RAW_SEQ AND EE.MEMB_SEQ = FF.MEMB_SEQ INNER JOIN T_RAW_MST AA ON AA.RAW_SEQ = FF.RAW_SEQ
AND FF.RAW_DETAIL_SEQ = #{rawDetailSeq, jdbcType=INTEGER}

/* com.erns.coching.raw.mapper.RawDAO.getGarbageList */

SELECT B.* FROM (
SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() AS TOTAL FROM (
SELECT

FROM  T_RAW_MST AA
INNER JOIN T_MEMB_INF MI
ON AA.RGTR = MI.MEMB_SEQ



order by AA.CHNG_DTTM desc
) A
) B

	WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

/* com.erns.coching.raw.mapper.RawDAO.getCmTypeList */ SELECT GRP_CODE, CODE, CODE_NM_KO, CODE_NM_EN, INPT_TYPE, SORT_ORD FROM T_CM_RAW_TYPE
AND USE_YN = 'Y'
ORDER BY GRP_CODE, CODE, SORT_ORD ASC

mapper.update:
		/* com.erns.coching.raw.mapper.RawDAO.updateState */

    	UPDATE T_RAW_MST SET
				USE_YN 	 = #{useYn, jdbcType=CHAR}

				, CHNR		= #{chnr, jdbcType=INTEGER}
				, CHNG_DTTM	= now()

			AND RAW_SEQ 	= #{rawSeq, jdbcType=INTEGER}
